const incident = $json.body;
const serviceName = incident.events[0]?.metadata?.service || 'unknown service';
const restartCount = incident.events[0]?.metadata?.restarts || 0;

// En un escenario real, aquí podríamos ejecutar `docker logs <serviceName>`
console.log(`[CRASH ALERT] Container '${serviceName}' is in a crash loop (${restartCount} restarts). Simulating log retrieval...`);

// Pasamos la data del incidente y los datos extraídos al siguiente nodo.
return [{ json: { incident, serviceName, restartCount } }];

